#include <iostream>
using namespace std;
int n;
char s[1111][1111];
int main() {
	int a,b;
	cin>>a>>b;
	for(int i=0; i<a; i++) {
		for(int j=0; j<b; j++) {
			cin>>s[i][j];
		}
	}
	for(int i=0; i<a; i++) {
		for(int j=0; j<b; j++) {
			if(s[i][j]=='h') {
				if(s[i+1][j]=='e'&&s[i+2][j]=='h'&&s[i+3][j]=='e') {
					n++;
				}
				if(s[i-1][j]=='e'&&s[i-2][j]=='h'&&s[i-3][j]=='e') {
					n++;
				}
				if(s[i][j+1]=='e'&&s[i][j+2]=='h'&&s[i][j+3]=='e') {
					n++;
				}
				if(s[i][j-1]=='e'&&s[i][j-2]=='h'&&s[i][j-3]=='e') {
					n++;
				}
			}
		}
	}
	cout<<n;
	return 0;
}
